#[doc = " Meta information about a particular importer. Importers need to fill"]
#[doc = "  this structure, but they can freely decide how talkative they are."]
#[doc = "  A common use case for loader meta info is a user interface"]
#[doc = "  in which the user can choose between various import/export file"]
#[doc = "  formats. Building such an UI by hand means a lot of maintenance"]
#[doc = "  as importers/exporters are added to Assimp, so it might be useful"]
#[doc = "  to have a common mechanism to query some rough importer"]
#[doc = "  characteristics."]
#[repr(C)]
#[derive(Debug, Copy, Clone, Hash, PartialEq, Eq)]
pub struct aiImporterDesc {
    #[doc = " Full name of the importer (i.e. Blender3D importer)"]
    pub mName: *const ::std::os::raw::c_char,
    #[doc = " Original author (left blank if unknown or whole assimp team)"]
    pub mAuthor: *const ::std::os::raw::c_char,
    #[doc = " Current maintainer, left blank if the author maintains"]
    pub mMaintainer: *const ::std::os::raw::c_char,
    #[doc = " Implementation comments, i.e. unimplemented features"]
    pub mComments: *const ::std::os::raw::c_char,
    #[doc = " These flags indicate some characteristics common to many"]
    #[doc = "importers."]
    pub mFlags: ::std::os::raw::c_uint,
    #[doc = " Minimum format version that can be loaded im major.minor format,"]
    #[doc = "both are set to 0 if there is either no version scheme"]
    #[doc = "or if the loader doesn't care."]
    pub mMinMajor: ::std::os::raw::c_uint,
    pub mMinMinor: ::std::os::raw::c_uint,
    #[doc = " Maximum format version that can be loaded im major.minor format,"]
    #[doc = "both are set to 0 if there is either no version scheme"]
    #[doc = "or if the loader doesn't care. Loaders that expect to be"]
    #[doc = "forward-compatible to potential future format versions should"]
    #[doc = "indicate  zero, otherwise they should specify the current"]
    #[doc = "maximum version."]
    pub mMaxMajor: ::std::os::raw::c_uint,
    pub mMaxMinor: ::std::os::raw::c_uint,
    #[doc = " List of file extensions this importer can handle."]
    #[doc = "List entries are separated by space characters."]
    #[doc = "All entries are lower case without a leading dot (i.e."]
    #[doc = "\"xml dae\" would be a valid value. Note that multiple"]
    #[doc = "importers may respond to the same file extension -"]
    #[doc = "assimp calls all importers in the order in which they"]
    #[doc = "are registered and each importer gets the opportunity"]
    #[doc = "to load the file until one importer \"claims\" the file. Apart"]
    #[doc = "from file extension checks, importers typically use"]
    #[doc = "other methods to quickly reject files (i.e. magic"]
    #[doc = "words) so this does not mean that common or generic"]
    #[doc = "file extensions such as XML would be tediously slow."]
    pub mFileExtensions: *const ::std::os::raw::c_char,
}
#[test]
fn bindgen_test_layout_aiImporterDesc() {
    assert_eq!(
        ::std::mem::size_of::<aiImporterDesc>(),
        64usize,
        concat!("Size of: ", stringify!(aiImporterDesc))
    );
    assert_eq!(
        ::std::mem::align_of::<aiImporterDesc>(),
        8usize,
        concat!("Alignment of ", stringify!(aiImporterDesc))
    );
    assert_eq!(
        unsafe { &(*(::std::ptr::null::<aiImporterDesc>())).mName as *const _ as usize },
        0usize,
        concat!(
            "Offset of field: ",
            stringify!(aiImporterDesc),
            "::",
            stringify!(mName)
        )
    );
    assert_eq!(
        unsafe { &(*(::std::ptr::null::<aiImporterDesc>())).mAuthor as *const _ as usize },
        8usize,
        concat!(
            "Offset of field: ",
            stringify!(aiImporterDesc),
            "::",
            stringify!(mAuthor)
        )
    );
    assert_eq!(
        unsafe { &(*(::std::ptr::null::<aiImporterDesc>())).mMaintainer as *const _ as usize },
        16usize,
        concat!(
            "Offset of field: ",
            stringify!(aiImporterDesc),
            "::",
            stringify!(mMaintainer)
        )
    );
    assert_eq!(
        unsafe { &(*(::std::ptr::null::<aiImporterDesc>())).mComments as *const _ as usize },
        24usize,
        concat!(
            "Offset of field: ",
            stringify!(aiImporterDesc),
            "::",
            stringify!(mComments)
        )
    );
    assert_eq!(
        unsafe { &(*(::std::ptr::null::<aiImporterDesc>())).mFlags as *const _ as usize },
        32usize,
        concat!(
            "Offset of field: ",
            stringify!(aiImporterDesc),
            "::",
            stringify!(mFlags)
        )
    );
    assert_eq!(
        unsafe { &(*(::std::ptr::null::<aiImporterDesc>())).mMinMajor as *const _ as usize },
        36usize,
        concat!(
            "Offset of field: ",
            stringify!(aiImporterDesc),
            "::",
            stringify!(mMinMajor)
        )
    );
    assert_eq!(
        unsafe { &(*(::std::ptr::null::<aiImporterDesc>())).mMinMinor as *const _ as usize },
        40usize,
        concat!(
            "Offset of field: ",
            stringify!(aiImporterDesc),
            "::",
            stringify!(mMinMinor)
        )
    );
    assert_eq!(
        unsafe { &(*(::std::ptr::null::<aiImporterDesc>())).mMaxMajor as *const _ as usize },
        44usize,
        concat!(
            "Offset of field: ",
            stringify!(aiImporterDesc),
            "::",
            stringify!(mMaxMajor)
        )
    );
    assert_eq!(
        unsafe { &(*(::std::ptr::null::<aiImporterDesc>())).mMaxMinor as *const _ as usize },
        48usize,
        concat!(
            "Offset of field: ",
            stringify!(aiImporterDesc),
            "::",
            stringify!(mMaxMinor)
        )
    );
    assert_eq!(
        unsafe { &(*(::std::ptr::null::<aiImporterDesc>())).mFileExtensions as *const _ as usize },
        56usize,
        concat!(
            "Offset of field: ",
            stringify!(aiImporterDesc),
            "::",
            stringify!(mFileExtensions)
        )
    );
}
