#[doc = " @brief  A skeleton bone represents a single bone is a skeleton structure."]
#[doc = ""]
#[doc = " Skeleton-Animations can be represented via a skeleton struct, which describes"]
#[doc = " a hierarchical tree assembled from skeleton bones. A bone is linked to a mesh."]
#[doc = " The bone knows its parent bone. If there is no parent bone the parent id is"]
#[doc = " marked with -1."]
#[doc = " The skeleton-bone stores a pointer to its used armature. If there is no"]
#[doc = " armature this value if set to nullptr."]
#[doc = " A skeleton bone stores its offset-matrix, which is the absolute transformation"]
#[doc = " for the bone. The bone stores the locale transformation to its parent as well."]
#[doc = " You can compute the offset matrix by multiplying the hierarchy like:"]
#[doc = " Tree: s1 -> s2 -> s3"]
