#[doc = ""]
#[doc = "  This is just a helper structure for the #AI_MATKEY_UVTRANSFORM key."]
#[doc = "  See its documentation for more details."]
#[doc = ""]
#[doc = "  Typically you'll want to build a matrix of this information. However,"]
#[doc = "  we keep separate scaling/translation/rotation values to make it"]
#[doc = "  easier to process and optimize UV transformations internally."]
